-- Modify "api_keys" table
ALTER TABLE "api_keys" ADD COLUMN IF NOT EXISTS "workspace_id" bigint NULL;
-- Create index "apikey_workspace_id_status" to table: "api_keys"
CREATE INDEX IF NOT EXISTS "apikey_workspace_id_status" ON "api_keys" ("workspace_id", "status");
-- Modify "users" table
ALTER TABLE "users" ADD COLUMN IF NOT EXISTS "workspace_id" bigint NULL;
-- Create index "user_workspace_id" to table: "users"
CREATE INDEX IF NOT EXISTS "user_workspace_id" ON "users" ("workspace_id");
-- Create "workspaces" table
CREATE TABLE IF NOT EXISTS "workspaces" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  "name" character varying NOT NULL,
  "slug" character varying NOT NULL,
  "owner_user_id" bigint NULL,
  "type" character varying NOT NULL DEFAULT 'personal',
  "status" character varying NOT NULL DEFAULT 'active',
  "metadata_json" jsonb NULL,
  PRIMARY KEY ("id")
);
-- Create index "workspace_owner_user_id_status" to table: "workspaces"
CREATE INDEX IF NOT EXISTS "workspace_owner_user_id_status" ON "workspaces" ("owner_user_id", "status");
-- Create index "workspace_slug" to table: "workspaces"
CREATE UNIQUE INDEX IF NOT EXISTS "workspace_slug" ON "workspaces" ("slug");
-- Create index "workspace_status" to table: "workspaces"
CREATE INDEX IF NOT EXISTS "workspace_status" ON "workspaces" ("status");
-- Backfill personal workspaces for existing users without one.
INSERT INTO "workspaces" ("created_at", "updated_at", "name", "slug", "owner_user_id", "type", "status")
SELECT NOW(), NOW(), COALESCE(NULLIF(TRIM("name"), ''), 'Personal') || ' Workspace', 'personal-' || "id"::text, "id", 'personal', 'active'
FROM "users"
WHERE "workspace_id" IS NULL
ON CONFLICT ("slug") DO NOTHING;
-- Attach existing users to their personal workspace.
UPDATE "users" AS "u"
SET "workspace_id" = "w"."id", "updated_at" = NOW()
FROM "workspaces" AS "w"
WHERE "u"."workspace_id" IS NULL
  AND "w"."owner_user_id" = "u"."id"
  AND "w"."type" = 'personal';
-- Attach existing API keys to the owner's workspace.
UPDATE "api_keys" AS "k"
SET "workspace_id" = "u"."workspace_id", "updated_at" = NOW()
FROM "users" AS "u"
WHERE "k"."workspace_id" IS NULL
  AND "k"."user_id" = "u"."id"
  AND "u"."workspace_id" IS NOT NULL;
